"use strict";(self.webpackChunknew_blog=self.webpackChunknew_blog||[]).push([[130],{7735:n=>{n.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"undergraduate-course-design","metadata":{"permalink":"/blog/undergraduate-course-design","source":"@site/blog/\u7efc\u5408\u8bfe\u7a0b\u8bbe\u8ba1\uff1a\u4ee4\u4eba\u611f\u53f9.md","title":"\u7efc\u5408\u8bfe\u7a0b\u8bbe\u8ba1\uff1a\u4ee4\u4eba\u611f\u53f9","description":"\u5927\u4e8c\u7684\u67d0\u795e\u5fc5\u8bfe\u7a0b\u9879\u76ee\u8bb0\u5f55\u3002","date":"2023-04-27T17:13:27.000Z","tags":[{"inline":false,"label":"UESTC","permalink":"/blog/tags/uestc","description":"\u6210\u7535\u751f\u6d3b"}],"readingTime":6.96,"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"undergraduate-course-design","title":"\u7efc\u5408\u8bfe\u7a0b\u8bbe\u8ba1\uff1a\u4ee4\u4eba\u611f\u53f9","date":"2023-04-27T17:13:27.000Z","tags":["uestc"]},"unlisted":false,"nextItem":{"title":"DevOps\u521d\u63a2--\u4e00\u6b21\u4e0d\u6210\u529f\u7684\u62db\u65b0\u7ecf\u5386","permalink":"/blog/devops-first"}},"content":"\u5927\u4e8c\u7684\u67d0\u795e\u5fc5\u8bfe\u7a0b\u9879\u76ee\u8bb0\u5f55\u3002\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n## \u5f00\u59cb\\r\\n\\r\\n\u7efc\u5408\u8bfe\u7a0b\u8bbe\u8ba1\u521a\u5f00\u59cb\u9009\u9898\u7684\u65f6\u5019\uff0c\u5b9a\u4f4d\u5230\u8d1f\u8d23\u6211\u4eec\u8fd9\u4e00\u5757\u7684\u67d0S\u8001\u5e08\u9879\u76ee\u5217\u8868\uff0c\u6240\u6709\u9879\u76ee\u51e0\u4e4e\u90fd\u548cCV\uff0c\u673a\u5668\u5b66\u4e60\u76f8\u5173\uff0c\u552f\u72ec\u4e00\u4e2a\u6587\u4ef6\u52a0\u5bc6\u4f20\u8f93\u5341\u5206\u663e\u773c\u30025\u96be\u5ea6\uff0c\u521a\u597d\u4e0a\u5b66\u671f\u4e0a\u8fc7\u5bc6\u7801\u5b66\u3002\u4e0d\u89c9\u5f97\u5f88\u9177\u5417\uff1f\u5f88\u7b26\u5408\u6211\u5bf9\u5206\u6570\u7684\u60f3\u8c61\u3002\\r\\n\\r\\n\u4e8e\u662f\u6211\u81ea\u4fe1\u6ee1\u6ee1\u7684\u9009\u4e86\uff0c\u6301\u7eed\u4e00\u4e2a\u6708\u7684\u5669\u68a6\u4e5f\u5f00\u59cb\u4e86\u3002\\r\\n\\r\\n\u7b2c\u4e00\u6b65\u81ea\u7136\u662f\u9009\u62e9\u5e93~~\u6211\u600e\u4e48\u4f1a\u5148\u60f3\u7740\u9020\u8f6e\u5b50~~\u3002\u9898\u76ee\u8981\u6c42`C++`\uff0c\u90a3\u56fe\u5f62\u5316\u8f6f\u4ef6\u5f88\u5bb9\u6613\u60f3\u5230Qt\uff1b\u800c\u5bc6\u7801\u5e93\u7684\u9009\u62e9\u5012\u662f\u4e00\u6ce2\u4e09\u6298\uff0c\u539f\u672c\u60f3\u7528\u6210\u719f\u7684OpenSSL\u7684\uff0c\u4f46\u5b66\u4e60\u6210\u672c\u6781\u5927\uff0c\u4e8e\u662f\u7ffb\u77e5\u4e4e\u7ffb\u5230\u73b0\u5728\u7528\u7684`CryptoPP`\u5e93\uff0c\u6709wiki\u6709\u793a\u4f8b\u4ee3\u7801\uff0c\u60f3\u8981\u7684\u52a0\u5bc6\u7b97\u6cd5\u4e00\u5e94\u4ff1\u5168\uff0c\u8fd8\u662f`C++`\u539f\u751f\u7684\uff0c\u592a\u597d\u4e86\uff0c\u5c31\u5b83\u4e86\uff01\\r\\n\\r\\n\u7136\u800c\u4e4b\u540e\u5927\u90e8\u5206\u7684bug\uff08\u6216\u8005\u8bf4\uff0c\u5168\u90e8\u607c\u4eba\u7684bug\uff09\u90fd\u6765\u6e90\u8fd9\u4e2a\u52a0\u5bc6\u5e93\u3002\u8fd9\u90e8\u5206\u6682\u4e14\u4e0d\u63d0\u3002\\r\\n\\r\\n`CryptoPP`\u5e93\u6ca1\u6709\u73b0\u6210\u7684lib\uff0c\u6362\u53e5\u8bdd\u8bf4\u9700\u8981\u81ea\u5df1\u7f16\u8bd1\u3002\u6253\u5f00\u5b83\u7684github\u4e0b\u8f7d\u6e90\u7801\uff0c\u53d1\u73b0\u8fd9\u73a9\u610f\u4f7f\u7528VS\u7f16\u8bd1\u7684\uff08~~\u4e0d\u7528CMAKE?~~\uff09,\u6e90\u7801\u91cc\u751a\u81f3\u6709\u4e13\u95e8\u63d0\u4f9b\u7ed9VS2005\u7684\u7528\u6237\u7684`sln`\u6587\u4ef6.\\r\\n\\r\\n\u597d\uff0c\u90a3\u6211\u5c31\u7528VS2022\u7ed9\u4f60\u7f16\u8bd1\u4e86\uff0c\u7136\u540e\u559c\u95fb\u4e50\u89c1\u7684\u62a5\u9519\u4e86\u3002\u7ffb\u7f51\u4e0a\u8d44\u6599\u53d1\u73b0\u8981\u7528VS2017\uff0c\u90a3\u5c31\u88c5\uff01(\u7535\u8111\u88abVS\u72c2\u66b4\u9e3f\u5112\u56db\u4e94\u6b21\u624d\u88c5\u597d\uff0c`C++`\u4e0b\u7684SDK\u786e\u5b9e\u96be\u7ef7)\\r\\n\\r\\n\u7f16\u8bd1\u597d\u4e86\uff08\u5df2\u7ecf\u8fc7\u53bb\u4e09\u56db\u5929\u4e86\uff09\uff0c\u914d\u73af\u5883\u90e8\u5206\u6700\u607c\u706b\u7684\u6765\u4e86\uff1a\u6211\u8be5\u600e\u4e48\u8ba9`Qt`\u548c`CryptoPP`\u9002\u914d\u5462\uff1f\\r\\n\u88c5\u4e86Qt\u4e03\u516b\u56de\uff0cQt\u8001\u7248\u672c\u7684VS\u53ea\u652f\u6301VS2015\u5957\u4ef6\uff0c\u800c\u65b0\u7248\u672c\u7684VS2017\u5957\u4ef6\u4e0d\u77e5\u9053\u600e\u4e48\u56de\u4e8b\u68c0\u6d4b\u4e0d\u5230\u672c\u5730\u7684VS2017 SDK\u3002\u6298\u817e\u4e86\u4e09\u56db\u5929\u624d\u6311\u51fa\u6765\u7b26\u5408\u7684Qt\u7248\u672c\uff0c\u4e4b\u540e\u53c8\u82b1\u4e86\u4e00\u5929\u5728Qt\u7684\u9879\u76ee\u914d\u7f6e\u6587\u4ef6`.pro`\u8fb9\u67e5\u8fb9\u5199,\u7ec8\u4e8e\u641e\u597d\u4e86VS2017 \u7f16\u8bd1\u7684`CryptoPP`\u5728windows\u4e0b\u5982\u4f55\u548cVS2017 SDK\u5957\u4ef6\u7684Qt\u4ee5\u53caqmake\u9002\u914d\u3002\\r\\n\\r\\n~~\u8fd9\u5c31\u662f\u88c5\u73af\u5883\uff0c\u542cdevops\u8bf4~~\\r\\n\\r\\n## \u7f51\u7edc\u901a\u4fe1\u90e8\u5206\uff08QT\uff09\\r\\n\\r\\n\u8fd9\u90e8\u5206\u5176\u5b9e\u6ca1\u5565\u597d\u8bf4\uff0c\u5404\u79cd\u6284\uff0c\u6284\u7740\u6284\u7740\u5c31\u628a\u81ea\u5df1\u8f6f\u4ef6\u7684\u6846\u67b6\u642d\u597d\u4e86\uff0c\u7136\u540e\u5728\u8fd9\u57fa\u7840\u4e0a\u6539\u4e86\u3002\\r\\n\u540e\u9762\u7ffb\u4e86\u4e0b\uff0c\u6211\u5728\u539f\u6765\u7684\u4ee3\u7801\u4e0a\u6539\u4e86\u633a\u591a\u7684\uff0c\u770b\u4e0a\u53bb\u786e\u5b9e\u548c\u539f\u6765\u4ee3\u7801\u5dee\u522b\u5f88\u5927\u3002socket\u4ece\u4e24\u4e2a\u5230\u4e09\u4e2a\u53c8\u5230\u4e24\u4e2a\uff0c\u8fd8\u7a0d\u5fae\u5b66\u4e86\u4e0bTCP\u7684\u7c98\u6ede\uff0c\u4ee5\u53caQt\u795e\u5947\u7684\u4fe1\u53f7\u548c\u69fd\u673a\u5236\u3002\\r\\n\\r\\n\u82e5\u628aTCP\u4f5c\u4e3a\u4e00\u79cd\u62bd\u8c61\u6d41\uff0c\u90a3\u4e48\u6211\u4eec\u662f\u65e0\u6cd5\u5206\u8fa8\u5176\u4e2d\u6570\u636e\u610f\u4e49\u7684\u3002\u82e5\u8981\u5206\u8fa8\uff0c\u5fc5\u987b\u4e8b\u5148\u77e5\u9053\u6587\u4ef6/\u6d88\u606f\u7684\u957f\u5ea6\uff0c\u7136\u540e\u518d\u6839\u636e\u957f\u5ea6\u8fdb\u884c\u622a\u65ad\u3002\\r\\n\u9700\u8981\u6307\u51fa\u7684\u662f\uff0c\u66b4\u9732\u5bc6\u6587\u7684\u957f\u5ea6\u5e76\u4e0d\u4f1a\u5f71\u54cd\u5b89\u5168\u6027\uff0c\u56e0\u6b64\u53ef\u4ee5\u5c06\u5bc6\u6587\u7684\u957f\u5ea6\u76f4\u63a5\u66b4\u9732\u5728\u4e0d\u5b89\u5168\u4fe1\u9053\u4e0b\u3002\\r\\n\\r\\nQt\u7684\u4fe1\u53f7\u4e0e\u69fd\u662f\u53ef\u4ee5\u53cd\u590d\u7ed1\u5b9a\u7684\u3002\u53cd\u590d\u7ed1\u5b9a\u5bf9\u4e8e\u67d0\u4e9b\u60c5\u51b5\u662f\u4e0d\u8981\u7d27\u7684\uff0c\u4f46\u5982\u679c\u4f60\u9700\u8981\u4fe1\u53f7\u7684\u53c2\u6570\uff0c\u8fd9\u5c31\u6709\u5927\u95ee\u9898\u3002\u6211\u5728\u4e00\u4e2a\u51fd\u6570\u91cc\u5199\u4e86connect\u8fdb\u884c\u4fe1\u53f7\u548c\u69fd\u7684\u7ed1\u5b9a\uff0c\u800c\u8be5\u51fd\u6570\u591a\u6b21\u8c03\u7528\u5bfc\u81f4\u4e00\u4e2a\u4fe1\u53f7\u548c\u591a\u4e2a\u69fd\uff08\u4f46\u5176\u5b9e\u662f\u4e00\u4e2a\uff09\u8fdb\u884c\u4e86\u7ed1\u5b9a\u3002\u4e8e\u662f\u69fd\u51fd\u6570\u4fbf\u6536\u5230\u4e86\u591a\u4e2a\u4fe1\u53f7\uff0c\u800c\u8fd9\u4e9b\u4fe1\u53f7\u90fd\u662f\u6765\u6e90\u4e8e\u540c\u4e00\u4e2a\u52a8\u4f5c\u51fd\u6570\u7684\u3002\\r\\n\\r\\n## \u5bc6\u7801\u5b66\u90e8\u5206\uff08CryptoPP\uff09\\r\\n\\r\\n\u5177\u4f53\u7ec6\u8282\u653e\u62a5\u544a\u91cc\u4e86\u4e0d\u60f3\u5199\uff0c\u8fd9\u91cc\u6311\u51e0\u4e2a`CryptoPP`\u7684\u795e\u5947bug\u7f62\u3002\\r\\n\\r\\n### \u4e2d\u6587\\r\\n\\r\\n\u8fd9\u4e2a\u5176\u5b9e\u8fd8\u597d\uff0c`CryptoPP`\u4e0d\u652f\u6301\u4e2d\u6587\u8def\u5f84\u548c\u4e2d\u6587\u540d\u7684\u6587\u4ef6\u52a0\u5bc6\u3002\u4f46\u8fd8\u662f\u53ef\u4ee5\u5410\u69fd\uff1a\u4e0d\u662f\u53ea\u5bf9\u6587\u4ef6\u5185\u90e8\u6570\u636e\u8fdb\u884c\u52a0\u5bc6\u7b7e\u540d\u5417\uff1f\u540d\u5b57\u6309\u4e8c\u8fdb\u5236\u5b58\u53d6\u4e0d\u884c\u5417\uff1f\\r\\n\\r\\n### RNG\\r\\n\\r\\n\u4e0d\u662f\u7535\u7ade\u90a3\u4e2a`RNG`\uff0chz\u6253\u6765\u6211\u5c31\u6295\u964d\u3002\\r\\n\\r\\n`RNG`\uff08Random number generator\uff09\uff0c\u5728\u5bc6\u7801\u5b66\u4e2d\u662f\u5341\u5206\u91cd\u8981\u7684\u4e00\u4e2a\u539f\u8bed\uff0c\u7528\u4e8e\u751f\u6210\u4f2a\u968f\u673a\u6570\uff0c\u7136\u800c`CryptoPP`\u7684`RNG`\u884c\u4e3a\u5341\u5206\u7279\u5f02\uff1a`RNG`\u5b9a\u4e49\u540e\u5fc5\u987b\u7acb\u5373\u4f7f\u7528\uff0c\u4e0d\u80fd\u653e\u5728\u5176\u4ed6\u5730\u65b9\uff08\u6bd4\u5982\u6211\u539f\u5148\u653e\u5728\u4e00\u4e2a\u7edf\u4e00\u7ba1\u7406\u7684`CryptoManager` class\u91cc\u5934\uff09\u5907\u7528\u3002\u5426\u5219`CryptoPP`\u81ea\u5df1\u63a8\u8350\u7684\u201c\u5bf9\u52a0\u8f7d\u7684\u5bc6\u94a5\u5fc5\u987b\u8fdb\u884c\u9a8c\u8bc1\uff08Valinate\uff0c\u8be5\u64cd\u4f5c\u63a5\u53d7\u4e00\u4e2a`RNG`\u548c\u4e00\u4e2a\u9a8c\u8bc1\u7ea7\u522b\u4f5c\u4e3a\u53c2\u6570\uff09\u201d\u4fbf\u4f1a`Runtime-error`.\\r\\n\\r\\n### DSA\\r\\n\\r\\nDSA\u662f\u5341\u5206\u7ecf\u5178\u7684\u6570\u5b57\u7b7e\u540d\u65b9\u6848\uff0c\u672c\u6765\u60f3\u5728\u8bfe\u8bbe\u91cc\u5b9e\u73b0\u4e00\u4e0b\u7684\u3002\u4f46`CryptoPP`\u5e93\u7684DSA\u5185\u90e8\u51fa\u73b0\u4e86\u95ee\u9898\uff1a\u6211\u5728\u540c\u4e00\u4efd\u4ee3\u7801\u91cc\u5bf9\u6587\u4ef6\u751f\u6210\u7b7e\u540d\uff0c\u4e4b\u540e\u7acb\u523b\u9a8c\u8bc1\uff0c\u76f4\u63a5RE\u3002\u540e\u9762~~\u7ecf\u8fc7\u8f93\u51fadebug\uff08ACM\u4e60\u60ef\u4e86\u5c5e\u4e8e\u662f\uff09~~\u5b9a\u4f4d\u5230`CryptoPP`\u5e93\u5185\u90e8\u51fa\u73b0\u95ee\u9898\uff0c\u6ca1\u5565\u529e\u6cd5\uff0c\u5220\u4e86\u7f62\u3002\\r\\n\\r\\n### RSA\\r\\n\\r\\nRSA\u4f5c\u4e3a\u516c\u94a5\u52a0\u5bc6\u65b9\u6848\uff0c\u540c\u65f6\u4e5f\u652f\u6301\u6570\u5b57\u7b7e\u540d\u3002\u4f46\u8fd0\u884c\u8fc7\u7a0b\u4e2d\uff0c`CryptoPP`\u5e93\u53c8\u51fa\u73b0\u4e86\u548cDSA\u4e00\u6837\u7684\u9519\u8bef\u3002\u5230\u8fd9\u91cc\u6211\u8fd8\u662f\u6ca1\u53d1\u73b0\u4e3a\u4ec0\u4e48\u6570\u5b57\u7b7e\u540d\u4f1a\u4ea7\u751f\u9519\u8bef\uff0c\u540e\u9762\u9009\u62e9ED25519\u4f5c\u4e3a\u6570\u5b57\u7b7e\u540d\u65b9\u6848\u7684\u65f6\u5019\u624d\u5076\u7136\u53d1\u73b0\uff0c\u53c8\u662f\u4f60\uff0c`RNG`\uff01\\r\\n\\r\\n`CryptoPP`\u5e93\u7684`RNG`\u652f\u6301\u6781\u5176\u4e0d\u5b8c\u5584\uff0c\u800c\u793a\u4f8b\u4ee3\u7801\u4e2d\uff0c\u6570\u5b57\u7b7e\u540d\u57fa\u672c\u90fd\u9700\u8981\u4f7f\u7528`RNG`\u4f5c\u4e3a\u53c2\u6570\u6765\u8fdb\u884c\u9a8c\u8bc1\u3002\u800cWIKI\u4e2d\u7684ED25519\u793a\u4f8b\u4ee3\u7801\u5341\u5206\u7279\u6b8a\u7684\u628a\u5bf9\u5e94\u7684`RNG`\u6362\u6210\u4e86`NullRNG`,\u8fd9\u5341\u5206\u5f62\u8c61\u7684\u540d\u5b57\uff0c\u4f7f\u5f97ED25519\u80fd\u591f\u987a\u5229\u8fdb\u884c\u7b7e\u540d\u3002\u4e8e\u662fED25519\u6210\u4e3a\u4e86\u8bfe\u8bbe\u91cc\u552f\u4e00\u7684\u6570\u5b57\u7b7e\u540d\u65b9\u6848\u3002\\r\\n\\r\\n\u770b\u5230\u8fd9\u91cc\u7684\u4f60\u5176\u5b9e\u4e5f\u660e\u767d\u4e86\uff0c\u7406\u8bba\u4e0aDSA\uff0cRSA\u8fd9\u4e24\u4e2a\u5f03\u7528\u7684\u6570\u5b57\u7b7e\u540d\u6539\u6539`RNG`\u5c31\u80fd\u6062\u590d\u4f7f\u7528\uff0c\u4f46\u6211\u61d2\u4e86\uff0c\u4e0d\u6539\u4e86\ud83d\ude07\\r\\n\\r\\n### ED25519\\r\\n\\r\\nED25519\u662f\u692d\u5706\u66f2\u7ebf\u6570\u5b57\u7b7e\u540d\u65b9\u6848\uff0c\u5176\u516c\u94a5\u5bc6\u94a5\u957f\u5ea6\u4e3a64/32 bytes\uff0c\u5728\u5176\u4ed6\u8bed\u8a00\u4e2d\u53ef\u4ee5\u81ea\u7531\u9009\u62e9\u8fd9\u4e24\u4e2a\u3002\\r\\n\\r\\n\u4f46`CryptoPP`\u4e0e\u4f17\u4e0d\u540c\uff1a\u5934\u6587\u4ef6\u5199\u660edefault\u60c5\u51b5\u4e0b\uff0cED25519\u5e94\u8be5\u751f\u621032bytes\u7684\u5bc6\u94a5\uff0c\u4f46\u5b83\u5b9e\u9645\u4e0a\u751f\u6210\u4e8656bytes\u7684\u5bc6\u94a5\uff0c\u524d\u9762\u591a\u51fa\u6765\u768424bytes\u662f\u4e0d\u53d8\u503c\u3002\\r\\n\\r\\n\u82e5\u6309\u7167\u793a\u4f8b\u4ee3\u7801\u6240\u5199\u8fdb\u884c\u7f16\u7a0b\uff0c\u90a3\u4e48\u5bc6\u94a5\u4e2d\u5c06\u4f1a\u5305\u542b24bytes\u7684\u786e\u5b9a\u503c\uff0c\u4ee5\u53ca8bytes\u7684\u968f\u673a\u503c\uff0c\u800c\u8fd9\u663e\u7136\u4f1a\u5f71\u54cd\u5230ED25519\u7684\u5b89\u5168\u6027\u3002\\r\\n\u800c\u88abDSA,RSA\uff0c\u4ee5\u53ca\u63a5\u4e0b\u6765\u7684GCM\u6467\u6b8b\u8bb8\u4e45\u7684\u6211\u653e\u5f03\u4e86\u4fee\u6539\uff08\u867d\u7136\u4fee\u6539\u786e\u5b9e\u4f1a\u6bd4\u8f83\u5bb9\u6613\uff09\uff0c\u591a\u4e00\u4e8b\u4e0d\u5982\u5c11\u4e00\u4e8b\uff0c\u4f55\u51b5\u8fd9ED25519\u80fd\u8dd1\u3002\u80fd\u8dd1\u5c31\u884c\uff0c\u4e0d\u5962\u671b\u592a\u591a\u4e86\u3002\\r\\n\\r\\n~~\u53cd\u6b63\u8001\u5e08\u4e5f\u770b\u4e0d\u61c2~~\\r\\n\\r\\n### GCM\\r\\n\\r\\nGCM\u662f\u5728\u5bf9\u79f0\u5bc6\u94a5\u52a0\u5bc6\u91cc\u5934\u7684\u64cd\u4f5c\u6a21\u5f0f\uff0c\u5b83\u63d0\u4f9b\u4e86AE\u5b89\u5168\u6027\uff0c\u56e0\u6b64\u6ee1\u8db3\u4e86CCA\u5b89\u5168...\\r\\n\\r\\n\u4ee5\u4e0a\u90e8\u5206\u6362\u6210\u4eba\u80fd\u542c\u61c2\u7684\uff0c\u5c31\u662f:GCM\u80fd\u591f\u63d0\u4f9b\u6bd4\u91c7\u53d6\u666e\u901a\u64cd\u4f5c\u6a21\u5f0f\u66f4\u5f3a\u7684\u5b89\u5168\u6027\uff0c\u800c\u8fd9\u90e8\u5206\u5b89\u5168\u6027\u7684\u6765\u6e90\uff0c\u5f88\u5927\u7a0b\u5ea6\u4e0a\u6765\u6e90\u4e8e\u5b83\u72ec\u7acb\u751f\u6210\u7684GMAC \u8ba4\u8bc1\u6807\u7b7e\uff0c\u8fd9\u662f\u5176\u4ed6\u64cd\u4f5c\u6a21\u5f0f\u6240\u6ca1\u6709\u7684\u3002\\r\\n\\r\\n\u8fd9\u4e48\u597d\u7684\u5b89\u5168\u6027\u81ea\u7136\u8981\u62ff\u6765\u7528\u4e86\u3002\u7167\u7740wiki\u4ee3\u7801\u6572\u4e00\u904d\uff0cRE...RE\uff1f\\r\\n\\r\\n\u7ffb\u4e86StackOverflow\uff0c\u53d1\u73b0\u793a\u4f8b\u4ee3\u7801\u662f\u9519\u7684\uff0c\u4ee3\u7801\u628aTag\u957f\u5ea6\u548cIV\u957f\u5ea6\u641e\u53cd\u4e86\u3002\u5443\u5443\ud83d\udca7\u3002\\r\\n\u6700\u79bb\u8c31\u7684\u662f\uff1a`CryptoPP` wiki\u4e13\u95e8\u5199\u4e86\uff1a\u521d\u59cb\u7684IV\u5411\u91cf\u53ef\u4ee5\u662f\u4efb\u610f\u957f\u5ea6\uff1b\u4f46\u5b9e\u9645\u8fc7\u7a0b\u4e2d\uff0cIV\u5fc5\u987b\u4e3a12\u5b57\u8282\u3002\\r\\n\\r\\n----\\r\\n\\r\\n\u53e6\u5916\u8fd8\u6709\u8bf8\u5982\u6307\u9488\u6ca1\u6709new\u53d8\u91cf\u5bfc\u81f4\u7a0b\u5e8f\u51fa\u73b0\u5947\u602abug\uff0c\u88ab\u9999\u80a0(orz)\u6307\u51fa\u540e\u5fc3\u6001\u70b8\u88c2\u7b49nt\u884c\u4e3a\uff0c\u6682\u4e14\u4e0d\u8868\u3002\\r\\n\\r\\n## Summary\\r\\n\\r\\n`CryptoPP`\u5e93\u6781\u5176\u96be\u7528\uff0c\u4e8e\u662f\u53ea\u80fd\u6311\u51e0\u4e2a\u6bdb\u75c5\u6700\u5c11\u7684\u65b9\u6cd5\u4f7f\u7528\u3002\u4f46\u6700\u672c\u8d28\u7684\u95ee\u9898\u5e76\u4e0d\u5728\u6b64\uff0c\u800c\u662f\uff1a\u4e3a\u4ec0\u4e48\u8981\u7528`C++`\u5f00\u53d1\uff1f\\r\\n\\r\\n`C++`\u6ca1\u6709\u5185\u7f6e\u7684\u5bc6\u7801\u5e93\uff0c\u6240\u4ee5\u6211\u53ea\u80fd\u6311\u4e0d\u9760\u8c31\u7684\u7b2c\u4e09\u65b9\u5e93\u4f5c\u4e3a\u4ee3\u66ff\uff0c\u800c\u5176\u4ed6\u8bed\u8a00\uff0c\u6bd4\u5982JS,C#,JAVA,\u8fd9\u4e9b\u90fd\u6709\u5341\u5206\u6210\u719f\u4e14\u73b0\u6210\u7684\u5bc6\u7801\u5e93\uff0c\u5e76\u4e14\u56fe\u5f62\u5316\u8f6f\u4ef6\u7f16\u5199\u66f4\u6bd4`C++`\u5bb9\u6613\u7684\u591a\u3002\u800c\u7533\u8bf7\u6539\u6362\u8bed\u8a00\u53ea\u8981\u548c\u8001\u5e08\u8bf4\u4e00\u53e5\u5c31\u884c\u4e86\u3002\\r\\n\\r\\n\u4e0d\u8fc7\u73b0\u5728\u60f3\u60f3\uff0c\u8001\u5e08\u53ef\u80fd\u5c31\u662f\u60f3\u8ba9\u4f60\u4ece\u5934\u9020\u8f6e\u5b50\uff0c\u800c\u4ece\u5934\u9020\u8f6e\u5b50\u51e0\u4e4e\u53ef\u4ee5\u8ba4\u4e3a\u662f\u4e3a\u96be\u672c\u79d1\u751f\uff0c\u4e0d\u4e9a\u4e8e\u4e00\u6b21CNSS Dev Boss\u9898\u7684\u96be\u5ea6\uff1a\u5199\u4e00\u4e2a\u51e0\u4e4e\u80af\u5b9a\u8981\u6709SIMD\u52a0\u901f\u7684\u57fa\u672c\u52a0\u5bc6\u5e93\u3002\\r\\n\\r\\n\u4f46\u6700\u540e\u8001\u5e08\u8fd8\u662f\u7ed9\u7528\u5e93\u540e\u7684\u621190\u4ee5\u4e0a\u5206\u6570\u3002\u4e5f\u8bb8\u7efc\u8bbe\u6574\u4e2a\u8bfe\u7a0b\u5c31\u662f\u4e2a\u7b11\u8bdd\uff0c\u54c8\u54c8\u3002"},{"id":"devops-first","metadata":{"permalink":"/blog/devops-first","source":"@site/blog/DevOps\u521d\u63a2--\u4e00\u6b21\u4e0d\u6210\u529f\u7684\u62db\u65b0\u7ecf\u5386.md","title":"DevOps\u521d\u63a2--\u4e00\u6b21\u4e0d\u6210\u529f\u7684\u62db\u65b0\u7ecf\u5386","description":"\u201c\u4f60\u6765\u661f\u8fb0\u6709\u9879\u76ee\u7ecf\u5386\u5417\u201d","date":"2022-12-25T15:48:00.000Z","tags":[{"inline":false,"label":"DevOps","permalink":"/blog/tags/devops","description":"DevOps\u76f8\u5173\u6742\u7c7b"},{"inline":false,"label":"Docker","permalink":"/blog/tags/docker","description":"Docker\u7b49\u5bb9\u5668\u76f8\u5173"}],"readingTime":9.69,"hasTruncateMarker":true,"authors":[],"frontMatter":{"slug":"devops-first","title":"DevOps\u521d\u63a2--\u4e00\u6b21\u4e0d\u6210\u529f\u7684\u62db\u65b0\u7ecf\u5386","date":"2022-12-25T15:48:00.000Z","tags":["devops","docker"]},"unlisted":false,"prevItem":{"title":"\u7efc\u5408\u8bfe\u7a0b\u8bbe\u8ba1\uff1a\u4ee4\u4eba\u611f\u53f9","permalink":"/blog/undergraduate-course-design"}},"content":"\u201c\u4f60\u6765\u661f\u8fb0\u6709\u9879\u76ee\u7ecf\u5386\u5417\u201d\\n\\n\u201c\u6ca1\u6709\uff0c\u4f46\u6211\u5f97\u8fdb\u4e86\u661f\u8fb0\u624d\u80fd\u6709\u9879\u76ee\u7ecf\u5386\u201d\\n\\n\x3c!-- truncate --\x3e\\n\\n\u65e0\u9879\u76ee\u7ecf\u5386\u8005\u4e0d\u5f97\u5165\u661f\u8fb0DevOps\u3002\\n\\n\u534a\u5f00\u73a9\u7b11\uff0c\u867d\u7136\u7b14\u8bd5\u5b8c\u6210\u7684\u81ea\u8ba4\u4e3a\u8fd8\u884c\uff0c\u4f46\u53ef\u80fd\u8fd8\u6709\u7f3a\u9677\uff0c\u8fd9\u91cc\u5c31\u653e\u4e0b\u7b49\u4e4b\u540e\u6709\u9879\u76ee\u7ecf\u5386\u4e86\u6765\u54c1\u9274\u4e00\u4e0b\u8fd9\u5768\u7b54\u8fa9\u5427\u3002DevOps\u770b\u91cd\u9879\u76ee\u7ecf\u5386\u5f53\u7136\u662f\u5f88\u6b63\u5e38\u7684\uff0c\u4f46\u6211\u6ca1\u60f3\u5230\u7684\u662f\u9762\u8bd5\u57fa\u672c\u4e0a\u53ea\u95ee\u8fd9\u4e00\u70b9\u3002\u8bc4\u5224\u6807\u51c6\u660e\u786e\u4e86\u90a3\u88ab\u8584\u7eb1\u4e5f\u662f\u5408\u60c5\u5408\u7406\u3002\\n\\n\u8fd9\u5c31\u662f\u5927\u4e00\u6446\u6ca1\u6709\u641e\u9879\u76ee\u7684\u4e0b\u573a.jpg\\n\\n\u8fc7\u7a0b\u622a\u56fe\u5c31\u4e0d\u653e\u4e86\uff0c\u8fd9\u91cc\u628a\u90e8\u5206\u9898\u76ee\u653e\u51fa\u6765\u3002\\n\\n\u76f8\u5173\u94fe\u63a5\uff1a\\n\\n[docker\u5b98\u65b9\u6587\u6863](https://docs.docker.com/)\\n[gitlab\u5b98\u65b9\u6587\u6863](https://docs.gitlab.com)\\n[gitlab\u5b98\u7f51](https://gitlab.com/)\\n[\u6211\u7684gitlab\u4e3b\u9875](https://gitlab.com/ZzzRemake)\\n\\n## \u547d\u4ee4\u884c\u5165\u95e8\\n\\n### \u601d\u8003\u9898 \u4e0e\u56fe\u5f62\u754c\u9762\u76f8\u6bd4\uff0c\u547d\u4ee4\u884c\u6709\u4ec0\u4e48\u4f18\u52bf\uff1f\\n\\n\u547d\u4ee4\u884c\u76f8\u6bd4\u56fe\u5f62\u754c\u9762\u6d88\u8017\u7684\u8d44\u6e90\u66f4\u5c11\uff0c\u80fd\u591f\u8ba9\u7528\u6236\u907f\u5f00\u56fe\u5f62\u754c\u9762\u7684\u6742\u4e71\uff08\u5904\u7406\u5927\u91cf\u6570\u636e\u7b49\u573a\u666f\uff09\u66f4\u4e13\u6ce8\u64cd\u4f5c\u547d\u4ee4\u3001\u4fe1\u606f\u7b49\u672c\u8d28\u9700\u6c42\uff0c\u64cd\u4f5c\u66f4\u52a0\u7075\u6d3b\uff1b\u4e14\u5728\u67d0\u4e9b\u65e0\u6cd5\u4f7f\u7528\u56fe\u5f62\u754c\u9762\u7a0b\u5e8f\u6216\u76f8\u5173\u8bbe\u65bd\u7684\u60c5\u51b5\u4e0b\uff0c\u547d\u4ee4\u884c\u5fc5\u4e0d\u53ef\u5c11\u3002\\n\\n\u987a\u5e26\u4e00\u63d0\uff0c\u8fd9\u91cc\u53ef\u4ee5\u53bb\u4e86\u89e3\u4e00\u4e0b\u5404\u5927Shell\u3002\\n\u6765\u4e2a\u77e5\u4e4e\u8fde\u63a5\uff1a[DavidZ\u7684\u56de\u7b54](https://www.zhihu.com/question/21418449/answer/2292448029)\\n\\n\u4e4b\u540e\u641e\u4e00\u4e2a\u4e13\u95e8\u7684\u547d\u4ee4\u884c\u5206\u7c7b\u5b66\u5b66\u7f62\u3002\\n\\n## Linux\u5b89\u88c5\u8f6f\u4ef6\\n\\n### docker\\n\\ndocker\u5b98\u65b9\u6587\u6863\u63d0\u4f9b\u4e86Docker desktop\u548cDocker Engine\u7684\u4e24\u79cd\u4e0b\u8f7d\u65b9\u5f0f\uff0c\u6211\u662f\u5b89\u88c5\u4e86Docker Engine\uff0c\u5e76\u4e14\u57fa\u672c\u6309\u7167\u5b98\u65b9\u6587\u6863\u7684\u6b65\u9aa4\u8fdb\u884c\u7684\u3002\\n\u6240\u6709\u6b65\u9aa4\u9644\u5728\u4ee5\u4e0b\u4ee3\u7801\u5757\u4e2d\uff0c\u5e76\u4ee5\u6ce8\u91ca\u6ce8\u660e\u8fc7\u7a0b\u3002\\n\\n```shell\\n# \u7b2c\u4e00\u6b65\uff0c\u5378\u8f7d\u65e7\u7248\u672c\uff08\u7136\u800c\u6211\u7684Ubuntu\u6839\u672c\u6ca1\u6709\uff09\\nsudo apt-get remove docker docker-engine docker.io containerd runc\\n# \u7b2c\u4e8c\u90e8\uff0c\u7531\u4e8e\u662f\u7b2c\u4e00\u6b21\u88c5\uff0c\u9700\u8981\u5efa\u7acb\u65b0\u7684Docker \u4ed3\u5e93\\n# 1.\u4f9d\u8d56\u9879\\nsudo apt-get update\\nsudo apt-get install ca-certificates curl gnupg lsb-release\\n# 2.curl add GPGkey\\nsudo mkdir -p /etc/apt/keyrings\\ncurl -fsSL https://download.docker.com/linux/ubuntu/gpg | sudo gpg --dearmor -o /etc/apt/keyrings/docker.gpg\\n# 3. \u5efa\u7acb\u4ed3\u5e93\\necho \\\\\\n\\"deb [arch=$(dpkg --print-architecture) signed-by=/etc/apt/keyrings/docker.gpg] https://download.docker.com/linux/ubuntu \\\\\\n$(lsb_release -cs) stable\\" | sudo tee /etc/apt/sources.list.d/docker.list > / dev/null\\n# \u7b2c\u4e09\u6b65\uff0c\u6b63\u5e38\u7684\u7528apt-get\u5b89\u88c5\\nsudo apt-get update\\nsudo apt-get install docker-ce docker-ce-cli containerd.io docker-compose-plugin\\n# \u6d4b\u8bd5\u4e00\u4e0b\uff1f\\nsudo docker run hello-world\\n```\\n\\n### \u601d\u8003\u9898 Linux\u4e0b\u5b89\u88c5\u8f6f\u4ef6\u4e0eWindows/macOS\u6709\u4ec0\u4e48\u533a\u522b\uff1f\\n\\nLinux\u53ef\u4ee5\u901a\u8fc7\u5305\u7ba1\u7406\u5de5\u5177\u65b9\u4fbf\u7684\u83b7\u53d6\u6700\u65b0\u7684\u8f6f\u4ef6\u5e76\u66f4\u65b0\uff0capt\u7b49\u5305\u7ba1\u7406\u5de5\u5177\u5728\u5b89\u88c5\u8f6f\u4ef6\u7684\u65f6\u5019\u53ef\u4ee5\u5b89\u88c5\u4f9d\u8d56\u9879\uff0c\u5927\u5927\u7b80\u5316\u4e86\u5b89\u88c5\u8f6f\u4ef6\u7684\u8fc7\u7a0b\u3002Windows\u5219\u662f\u901a\u8fc7\u4e0b\u8f7d\u53ef\u6267\u884c\u6587\u4ef6(exe)\u7b49\u65b9\u5f0f\u8fdb\u884c\u5b89\u88c5\uff0c\u65e0\u6cd5\u89e3\u51b3\u4f9d\u8d56\u95ee\u9898\uff0cLinux\u5f53\u7136\u4e5f\u6709\u7c7b\u4f3c\u7684\u5b89\u88c5\u5305\u76f4\u63a5\u5b89\u88c5\uff0c\u4e0d\u89e3\u51b3\u4f9d\u8d56\u7684\u65b9\u5f0f\uff0capt\u7b49\u5305\u7ba1\u7406\u4fbf\u6539\u5584\u4e86\u8fd9\u4e00\u70b9\u3002\\n\\n**\u540e\u6765\u4fee\u8ba2\u90e8\u5206**\\n\u5f53\u7136\uff0c\u8fd9\u91cc\u53ef\u4ee5\u6269\u5c55\u5f00\u8bb2\u3002dpkg\uff0cdeb\u4e4b\u7c7b\u7684\u3002\u3002emmm\uff0c\u5f52linux\u6863\uff1f\u548c\u5148\u524d\u90a3\u4e2a\u547d\u4ee4\u884c\u4e00\u8d77\u3002\\n\\n## \u7f51\u7edc\u76f8\u5173\\n\\n### \u601d\u8003\u9898 OSI\u4e03\u5c42\u6a21\u578b\u7684\u6570\u636e\u5904\u7406\u8fc7\u7a0b\\n\\n\u5e94\u7528\u5c42\uff1a\u5c06\u6570\u636e\u5448\u73b0\u7ed9\u7528\u6236\uff1b\u8868\u793a\u5c42\uff1a\u5c06\u63a5\u6536\u5230\u7684\u6570\u636e\u7f16\u7801\u89e3\u7801\u6210\u5e94\u7528\u5c42\u80fd\u8bfb\u53d6\u7684\u683c\u5f0f\uff0c\u4e5f\u53ef\u4ee5\u5bf9\u6570\u636e\u52a0\u5bc6\u89e3\u5bc6\uff1b\u4f1a\u8bdd\u5c42\uff1a\u518d\u4e24\u53f0\u4e3b\u673a\u95f4\u5efa\u7acb\u4f1a\u8bdd\u4ee5\u4f20\u8f93\u6570\u636e\u3002\\n\u4ee5\u4e0a\u5c42\u7684PDU\u90fd\u4e3a\u6570\u636e\uff08data\uff09\uff0c\u90fd\u662f\u548c\u5e94\u7528\u672c\u8eab\u76f8\u5173\u7684\u6570\u636e\u3001\u6d88\u606f\u62a5\u6587\u7b49\u3002\\n\u800c\u4f20\u8f93\u5c42\u5c06PDU\u5206\u6bb5\u4e3asegment\uff08TCP\uff09\u6216\u8005\u6570\u636e\u62a5datagram\uff08UDP\uff09\uff0c\u4e24\u8005\u5927\u5c0f\u90fd\u662f\u6709\u9650\u7684\u3002\u5206\u6bb5\u524d\u8fdb\u884c\u6570\u636e\u5c01\u88c5\uff0c\u52a0\u4e0aTCP\u6216UDP\u7b49\u6709\u5173\u4fe1\u606f\u3002\\n\u7f51\u7edc\u5c42\u5c06\u6570\u636e\u5934\u52a0\u4e0aIP\u4fe1\u606f\uff0c\u5305\u542b\u4e86\u903b\u8f91\u5bfb\u5740\u7684\u4fe1\u606f\uff0c\u4e4b\u540e\u5c06\u5904\u7406\u540e\u7684PDU\uff1a\u5305\uff08Packet\uff09\u4f20\u8f93\u7ed9\u6570\u636e\u94fe\u8def\u5c42\u3002\\n\u6570\u636e\u94fe\u8def\u5c42\u7684PDU\u5f62\u5f0f\u4e3a\u5e27\uff08frame\uff09\uff0c\u5176\u4e2d\u52a0\u4e0a\u4e86LLC\u5934\uff08\u4e0e\u786c\u4ef6\u65e0\u5173\uff09\u548cMAC\u5934\uff08\u5bfb\u5740\u7b49\u786c\u4ef6\u76f8\u5173\uff09\uff1b\u7269\u7406\u5c42\u5219\u5c06\u6570\u636e\u5904\u7406\u4e3a\u4e8c\u8fdb\u5236\u6d41\u6570\u636e\u4f4d\uff08bit\uff09\\n\\n### \u5b9e\u8df5\u9898 Linux\u914d\u7f6e\u8def\u7531\u8bbf\u95ee\u5916\u7f51\\n\\nNAT\u6a21\u5f0f\u4e0b\u7684linux\u865a\u62df\u673a\u65e0\u6cd5\u5b8c\u6210\u4efb\u52a1\uff0c\u56e0\u6b64\u5c06\u865a\u62df\u673a\u5207\u6362\u6210\u6865\u63a5\u6a21\u5f0f\u3002\\n\u7136\u800c\uff0c\u6865\u63a5\u6a21\u5f0f\u4e0b\u7684\u865a\u62df\u673a\u7684\u9ed8\u8ba4\u8def\u7531\u662f\u6ca1\u6709\u4efb\u4f55\u591a\u4f59\u8bbe\u7f6e\u7684\uff0c\u56e0\u6b64\uff0c\u5728\u53d6\u6d88NAT\u7684\u8bbe\u7f6e\u540e\uff0c\u7f51\u5361\u7684\u8def\u7531\u65e0\u6cd5\u6539\u53d8\uff0c\u5728\u5bbf\u4e3b\u673a\u5207\u6362WIFI\u7684\u65f6\u5019\u4fbf\u56e0\u4e3a\u6ca1\u6709\u5408\u6cd5IP\u5730\u5740\u800c\u65e0\u6cd5\u8054\u7f51\u3002\uff08\u5927\u6982\u3002\u3002\u7b26\u5408\u9898\u76ee\u8981\u6c42\uff1f\uff09\\n\u4e8e\u662f\u5728`/etc/netplan`\u6587\u4ef6\u5939\uff08\u65b0\u7248\u7684Ubuntu\u7f51\u7edc\u914d\u7f6e\u6587\u4ef6\u4e0e\u5176\u4ed6\u7cfb\u7edf\u4e0d\u540c\uff09\u627e\u5230yaml\u5e76\u4fee\u6539\uff1a\\n\\n```yaml\\nnetwork: \\n    version: 2\\n    renderer: NetworkManager\\n    ethernets:\\n        ens33:\\n            dhcp4: true\\n            dhcp6: true\\n```\\n\\n\u8fd9\u91cc\u7528dhcp\u52a8\u6001\u914d\u7f6eip\uff0cens33\u8868\u793a\u7f51\u5361\u3002emmm\uff0c\u5176\u4ed6\u7684\u8fd8\u662f\u9700\u8981\u67e5\u4e00\u4e0b\u7684\u3002\\n\\n\u4e4b\u540e\u865a\u62df\u673a\u548c\u4e3b\u673a\u80fd\u591fping\u901a\uff0c\u4e5f\u80fd\u591f\u8bbf\u95ee\u5916\u7f51\u3002\\n\\n### \u9009\u505a\u9898 \u8bf7\u7b80\u8ff0\u4e8c\u5c42\u4ea4\u6362\u673a\u3001\u4e09\u5c42\u4ea4\u6362\u673a\u3001\u8def\u7531\u5668\u4e4b\u95f4\u7684\u533a\u522b\uff0c\u4ee5\u53ca\u5b83\u4eec\u4e00\u822c\u88ab\u90e8\u7f72\u5728\u7f51\u7edc\u7684\u54ea\u4e9b\u4f4d\u7f6e\u4e0a\\n\\n\u4e8c\u5c42\u4ea4\u6362\u673a\u4f4d\u4e8eOSI\u7b2c\u4e8c\u5c42\uff0c\u53ef\u4ee5\u7528MAC\u5730\u5740\u8f6c\u53d1\u6570\u636e\uff08\u53ef\u4f20\u8f93\u5230\u5355\u4e00\u4e3b\u673a\uff0c\u4e0e\u96c6\u7ebf\u5668\u7684\u5e7f\u64ad\u533a\u5206\uff09\uff0c\u53ef\u4ee5\u7528\u4e8eVLAN\u7b49\u65b9\u5f0f\u5212\u5206\u5e7f\u64ad\u57df\uff1b\u4e09\u5c42\u4ea4\u6362\u673a\u5728\u52a0\u4e0a\u4e86\u8def\u7531\u6a21\u5757\uff0c\u4ece\u800c\u52a0\u901f\u8f6c\u53d1\u6570\u636e\u5305\u7684\u8fc7\u7a0b\uff08\u4e00\u6b21\u8def\u7531\uff0c\u591a\u6b21\u8f6c\u53d1\uff09\u3002\\n\u7136\u800c\uff0c\u4e09\u5c42\u4ea4\u6362\u673a\u53ea\u80fd\u90e8\u5206\u5b9e\u73b0\u8def\u7531\u5668\u7684\u529f\u80fd\u3002\u8fde\u63a5WAN\u7684\u8def\u7531\u5668\u6240\u9700\u7ef4\u62a4\u7684\u8868\u9879\u5341\u5206\u5e9e\u5927\u4e14\u5b58\u5728\u5237\u65b0\u7684\u53ef\u80fd\uff0c\u8fd9\u5bf9\u4e09\u5c42\u4ea4\u6362\u673a\u6765\u8bf4\u4efb\u52a1\u8fc7\u4e8e\u7e41\u91cd\uff0c\u4e14\u5927\u91cf\u7684\u6570\u636e\u4e5f\u5bf9\u5176\u52a0\u901f\u8f6c\u53d1\u7684\u6027\u80fd\u6709\u8f83\u5927\u5f71\u54cd\uff0c\u56e0\u800c\u8fd9\u90e8\u5206\u7531\u8def\u7531\u5668\u627f\u62c5\u3002\u540c\u65f6\uff0c\u8def\u7531\u5668\u53ef\u4ee5\u63d0\u4f9b\u7f51\u7edc\u5b89\u5168\u3001\u9664TCP/IP\u5916\u7684\u7f51\u7edc\u534f\u8bae\u7b49\u529f\u80fd\uff0c\u8fd9\u4e9b\u90fd\u662f\u4e09\u5c42\u4ea4\u6362\u673a\u6240\u65e0\u6cd5\u505a\u5230\u7684\u3002\\n\\n**\u4e8c\u6b21\u4fee\u8ba2**:\\n\u5b9e\u9645\u4e0a\uff0c\u8fd9\u91cc\u7684\u4e8c\u5c42\u3001\u4e09\u5c42\u4ea4\u6362\u673a\u53ef\u4ee5\u548c\u5f88\u591a\u6982\u5ff5\u6302\u94a9\u3002\u5173\u4e8e\u4ea4\u6362\u673a\u7684\u533a\u522b\uff0c\u53ef\u4ee5\u770b\u8fd9\u4e2a\u535a\u5ba2\uff1a\\n[Vlan/Trunk\u4ee5\u53ca\u4e09\u5c42\u4ea4\u6362](https://blog.csdn.net/dog250/article/details/8219141)\\n\u5173\u4e8evlan\uff0c\u53ef\u4ee5\u770b\u8fd9\u4e2a[\u539f\u7406\u8be6\u89e3](https://blog.csdn.net/phunxm/article/details/9498829).\\n\\n!!! info \u63a8\u8350\u4e66\u7c4d\\n    \u5c31\u662f\u4f60\u7535\u8bfe\u672c\uff0c\u5927\u9ed1\u76ae\u662f\u771f\u4e0d\u9519\u3002\\n    **\u300a\u8ba1\u7b97\u673a\u7f51\u7edc\uff1a\u81ea\u9876\u5411\u4e0b\u65b9\u6cd5\u300b**\\n\\n### \u9644\u52a0\u9898\\n\\n\u5b9e\u9645\u4e0a\u8fd9\u4e2a\u9644\u52a0\u9898\u4e0d\u662fDevOps\u91cc\u5934\u7684\uff0c\u6211\u4ece\u7f51\u7ba1\u4f1a\u90a3\u91cc\u642c\u4e00\u4e2a\u653e\u5728\u8fd9\uff0c\u611f\u89c9\u662f\u5f88\u597d\u73a9\u7684\u3002\\n\\n**DH42\u7f51\u7edc\u914d\u7f6e**\\n[lantian\'s blog](https://lantian.pub/article/modify-website/dn42-experimental-network-2020.lantian/)\\n\u5495\u5495\u5495\uff0c\u7b49\u6709\u65f6\u95f4\u641e\u3002\\n\\n## docker\u5bb9\u5668\\n\\n### \u5b9e\u8df5\u9898 \u5728docker\u4e2d\u8fd0\u884cphpmyadmin\u5bb9\u5668\\n\\n!!! info \u63d0\u793a\\n    phpmyadmin\u662f\u4e00\u4e2aWeb\u7aef\u7684\u6570\u636e\u5e93\u53ef\u89c6\u5316\u754c\u9762\uff0c\u5b83\u9700\u8981\u6307\u5b9aMySQL\u670d\u52a1\u5668\u7684IP\u5730\u5740\uff0c\u901a\u8fc7\u8bbe\u7f6e\u5bb9\u5668\u7684\u73af\u5883\u53d8\u91cf`PMA_HOST`\u6765\u6307\u5b9a\u3002\u5982\u679c\u4f60\u662f\u5728Linux\u73af\u5883\uff0c\u90a3\u4e48docker\u4f1a\u6709\u4e00\u4e2a\u5b50\u7f51\uff0c\u4e00\u822c\u662f`172.16.0.0/16`\u7f51\u6bb5\uff0c\u521a\u624d\u8fd0\u884c\u7684mariaDB\u5bb9\u5668\u4f1a\u5f97\u5230\u4e00\u4e2aIP\u5730\u5740\uff0c\u4f60\u53ef\u4ee5\u901a\u8fc7`docker ps`\u547d\u4ee4\u67e5\u770b\u5f53\u524d\u8fd0\u884c\u7684\u5bb9\u5668\u4fe1\u606f\uff0c\u7136\u540e\u901a\u8fc7`docker inspect` \u5bb9\u5668ID\u67e5\u770b\u5bb9\u5668\u7684IP\u5730\u5740\u3002\u5982\u679c\u4f60\u662f\u5728macOS\u4e0a\u8fd0\u884cdocker\uff0c\u9700\u8981\u6ce8\u610f\u7531\u4e8emacOS\u4e0d\u5177\u5907docker\u6240\u9700\u8981\u7684namespace\u548ccgroup\uff0c\u6240\u4ee5macOS\u4e0a\u7684docker\u5b9e\u9645\u662f\u8fd0\u884c\u5728VirtualBox\u865a\u62df\u673a\u4e2d\u7684\uff0c\u800c\u4e14\u5b83\u7684\u7f51\u7edc\u4e0e\u5bbf\u4e3b\u673a\u7f51\u7edc\u5e76\u4e0d\u76f4\u63a5\u8fde\u901a\uff0c\u597d\u5728\u5bb9\u5668\u4e4b\u95f4\u7684\u7f51\u7edc\u662f\u8fde\u901a\u7684\uff0c\u4f46\u662f\u5bf9\u4e8ephpmyadmin\uff0c\u4f60\u53ef\u80fd\u9700\u8981\u5c06\u5b83\u7684Web\u7aef\u53e3\uff0880\uff09\u6620\u5c04\u5230\u672c\u673a\u7684\u5176\u4ed6\u7aef\u53e3\u4e0a\uff0c\u53ef\u4ee5\u7528\u53c2\u6570 `-p` \u5bbf\u4e3b\u673a\u7aef\u53e3:\u5bb9\u5668\u7aef\u53e3 \u6307\u5b9a\u3002\\n\\n```shell\\n# docker \u521b\u5efa\u7f51\u7edc\\nsudo docker network create my-mariadb\\n# \u521b\u5efamariadb\uff0c\u6307\u5b9a\u73af\u5883\u53d8\u91cfMYSQL_ROOT_PASSWORD\u3001\u7aef\u53e3\u6620\u5c04\u3001\u547d\u540d\u5377\u548c\u7f51\u7edc\u522b\u540d\\nsudo docker run -d \\\\\\n--restart always \\\\\\n--network my-mariadb --network-alias mariadb \\\\\\n-e MYSQL_ROOT_PASSWORD=123456 \\\\\\n-p 3306:3306 \\\\\\n-v mariadb-data:/var/lib/mysql \\\\\\nmariadb\\n# \u521b\u5efaphpmyadmin\uff0c\u6307\u5b9a\u73af\u5883\u53d8\u91cfPMA_HOST\u3001\u7aef\u53e3\u6620\u5c04\u548c\u7f51\u7edc\u522b\u540d\\nsudo docker run -d \\\\\\n--restart always \\\\\\n--network my-mariadb --network-alias phpmyadmin \\\\\\n-p 8081:80 \\\\\\n-e PMA_HOST=mariadb \\\\\\nphpmyadmin\\n```\\n\\n### \u601d\u8003\u9898 docker\u548c\u865a\u62df\u673a\u6709\u4ec0\u4e48\u4e0d\u540c\uff1f\\n\\ndocker\u901a\u8fc7docker\u5b88\u62a4\u8fdb\u7a0b\u6765\u7ba1\u7406docker\u5bb9\u5668\uff0c\u901a\u8fc7linux\u7684namespace\u7ec4\u5408\u548ccgroups\u6765\u9694\u79bbdocker\u5185\u5916\u548c\u7ba1\u7406\u6240\u7528\u8d44\u6e90\u3002docker\u53ef\u4ee5\u5c06\u5e94\u7528\u7a0b\u5e8f\u6240\u8fd0\u884c\u5b58\u50a8\u7684\u6570\u636e\u901a\u8fc7\u5206\u5c42\u6765\u9694\u79bb\uff0cpush\u548cpull\u955c\u50cf\u7684\u65f6\u5019\u4e0d\u4f1a\u5f71\u54cd\uff0c\u901a\u8fc7\u6570\u636e\u5377\u6302\u8f7d\u6765\u6301\u4e45\u5316\u6570\u636e\u3002\u7136\u800c\u5176\u9694\u79bb\u6027\u65e0\u6cd5\u6bd4\u62df\u865a\u62df\u673a\u3002\\n\u800c\u865a\u62df\u673a\u662f\u901a\u8fc7Hypervisor\u7ba1\u7406\u865a\u62df\u673a\u7cfb\u7edf\uff0c\u76f4\u63a5\u8bbf\u95ee\u786c\u4ef6\u8d44\u6e90\uff0c\u5e76\u8f83docker\u9700\u8981\u66f4\u591a\u7684\u5b58\u50a8\u7a7a\u95f4\u7b49\u786c\u4ef6\u8d44\u6e90\u3002\u865a\u62df\u673a\u5728\u8fd0\u884c\u7684\u65f6\u5019\u9700\u8981\u8fd0\u884c\u5404\u79cd\u4f9d\u8d56\uff0c\u76f8\u8f83docker\u53ef\u4ee5\u4e13\u6ce8\u5355\u4e2a\u5e94\u7528\u800c\u8a00\u66f4\u53ef\u80fd\u53d1\u751f\u51b2\u7a81\uff0c\u542f\u52a8\u65f6\u95f4\u4e5f\u6bd4\u62df\u4e0d\u4e86docker\u7684\u5feb\u6377\u3002\\n\\n**\u4e8c\u6b21\u4fee\u8ba2**:\\n\u5173\u4e8edocker\u76f8\u5173\uff0c\u9664\u4e86\u6700\u4e0a\u65b9\u7684\u5b98\u65b9\u6587\u6863\u6559\u7a0b\uff08\u65b0\u4eba\u53cb\u597d\uff09\uff0c\u8fd8\u6709\u76f8\u5173\u7684[\u4ecb\u7ecd](https://www.lixl.cn/books/Docker/1-Overview/#docker_7)\\n\\n## GitLab CI/CD\\n\\ngit\u64cd\u4f5c\u8fd9\u91cc\u5c31\u4e0d\u653e\u4e86\uff08\\n\\n### \u5b9e\u8df5\u9898 \u4f7f\u7528GitLab CI/CD\u529f\u80fd\uff0c\u5b9e\u73b0Docker\u955c\u50cf\u81ea\u52a8\u53d1\u5e03\\n\\n[\u770b\u770b\u9879\u76ee](https://gitlab.com/ZzzRemake/hello_devops)\\n\u5177\u4f53\u5df2\u7ecf\u5199readme\u91cc\u5934\u4e86\u3002\\n\\n### \u601d\u8003\u9898 \u5982\u4f55\u5c06Docker\u955c\u50cf\u5b9e\u9645\u5728\u670d\u52a1\u5668\u4e0a\u8fd0\u884c\uff1f\\n\\n\u4f3c\u4e4e\u662f\u4e00\u4e2a\u86ee\u6df1\u5965\u7684\u95ee\u9898\uff0c\u4f46\u6211\u6ca1\u6709\u9879\u76ee\u5f00\u53d1\u7ecf\u9a8c\uff08\u8fd9\u5c31\u662f\u5927\u4e00\u6446\u6ca1\u6709\u641e\u9879\u76ee\u7684\u4e0b\u573a.jpgx2\uff09\uff0c\u8fd9\u91cc\u53ea\u80fd\u653e\u7f51\u4e0a\u67e5\u5230\u7684\u73a9\u610f\u513f\u4e86\u3002\\n\\n\u521b\u5efa\u955c\u50cf\u540e\u5df2\u7ecf\u53d1\u5e03\u5230\u4e86docker hub\uff0c\u56e0\u6b64\u53ef\u4ee5\u8ba9\u670d\u52a1\u5668\u5220\u9664\u539f\u6709\u7684\u53ef\u80fd\u51b2\u7a81\u7684\u955c\u50cf\uff0c\u7136\u540e\u4ecedocker hub\u62c9\u53d6\u6240\u9700\u955c\u50cf\u8fd0\u884c\u5bb9\u5668\u3002\\n\\n### \u5b9e\u8df5\u9898 \u642d\u5efa\u535a\u5ba2\u7f62\\n\\n[\u535a\u5ba2\u94fe\u63a5](https://zzzremake.gitlab.io/)\\n\\n[\u4ed3\u5e93\u94fe\u63a5](https://gitlab.com/ZzzRemake/zzzremake.gitlab.io)\\n\\n\u4e4b\u524d\u5df2\u7ecf\u5728windows\u73af\u5883\u4e0b\u5199\u8fc7\u4e00\u6b21github page\u90e8\u7f72hexo\u535a\u5ba2\uff08\u5c31\u662f\u4f60\u73b0\u5728\u770b\u5230\u7684\u535a\u5ba2\uff09\u4e86\uff0c\u4f46`node_modules/`\u4ee5\u53ca\u76f8\u5173\u7684\u5305\u7531\u4e8e\u90fd\u662fjs\u7b49\u6587\u4ef6\uff0c\u7406\u8bba\u4e0a\u662f\u53ef\u4ee5\u8de8\u5e73\u53f0\u7684\uff0c\u56e0\u6b64\u6211\u76f4\u63a5\u8bd5\u4e86\u4e0bcopy\uff0c\u8fd8\u771f\u884c\uff0c\u4e50\uff08\\n\u4e8e\u662f\u4fbf\u628a\u76f8\u5173\u6587\u4ef6copy\u5230\u4e86\u865a\u62df\u673a\u4e2d\uff0c\u4e14\u5728gitlab\u7f51\u2eda\u91cc\u65b0\u5efa\u4e86\u521b\u5efapage\u7684project\u3002\u63a5\u4e0b\u6765\u7684\u6b65\u9aa4\u548c\u4e4b\u524d\u7528`gitlab CI/CD` \u529f\u80fd\u90e8\u7f72docker\u955c\u50cf\u76f8\u4f3c\u3002\u7f16\u5199`.gitlab-ci.yml`\u65f6\uff0c\u53d1\u73b0gitlab\u6709\u63d0\u4f9bhexo\u7684\u6a21\u677f\\nyml\uff0ccopy\u540e\u7531\u4e8enode\u7248\u672c\u4e0d\u540c\u4fee\u6539\u4e86\u6a21\u677f\u7684image\u4fe1\u606f\uff0c\u63d0\u4ea4\u540e\u4fbf\u53ef\u901a\u8fc7pipeline\u751f\u6210\u535a\u5ba2\u3002\\n\\n**problems**:\\n\u5728\u6ce8\u518cgitlab-runner\u7684\u65f6\u5019\uff0c\u6211\u539f\u672c\u4ee5\u4e3a\u9700\u8981\u518d\u5728\u672c\u5730\u521b\u5efa\u4e00\u4e2agitlab-runner\u7684docker\u6765\u642d\u914d\u535a\u5ba2\u4ed3\u5e93\u7684\u6d41\u6c34\u7ebf\uff0c\u4f46\u6ce8\u518c\u540e\u67e5\u770b\u914d\u7f6e\u6587\u4ef6\uff0c\u53d1\u73b0\u662f\u5728\u914d\u7f6e\u6587\u4ef6\u4e2d\u65b0\u6dfb\u52a0\u4e86\u5173\u4e8e\u535a\u5ba2\u4ed3\u5e93\u914d\u7f6erunner\u7684\u4fe1\u606f.\\n\\n\u53e6\u5916\uff0ccopy\u540e\u53d1\u73b0\u4f7f\u7528\u7684\u4e3b\u9898\u6587\u4ef6\u5939`theme/hexo-theme-matery`\u91cc\u9762\u662f\u6709`git`\u5b50\u4ed3\u5e93\u7684\uff0c\u5982\u679c\u4e0d\u5220\u9664\u5176\u4e2d\u7684`.git`\u6587\u4ef6\u5939\uff0cpush\u5230gitlab\u4e0a\u4f1a\u65e0\u6cd5\u6253\u5f00\u5176\u4e2d\u7684\u6587\u4ef6\uff08\u65e0url\uff09\uff0c\u6d41\u6c34\u7ebf\u521b\u5efa\u7684\u8fc7\u7a0b\u4e5f\u4f1a\u5931\u8d25\u3002\u7531\u4e8e\u535a\u5ba2\u9879\u76ee\u672c\u8eab\u4e0d\u662f\u4e00\u4e2a\u590d\u6742\u9879\u76ee\uff08\uff1f\uff0c\u56e0\u6b64\u5220\u53bb\u8fd9\u91cc\u7684\u5b50\u4ed3\u5e93\uff0c\u7528\u4e3b\u4ed3\u5e93\u76f4\u63a5\u7ba1\u7406\u3002\\n\\n**\u4e8c\u6b21\u4fee\u8ba2**:\\n\u6ca1\u9519\uff0c\u8fd9\u5c31\u662f\u4e2a\u7b80\u5355\u7684\u590d\u5236\u7c98\u8d34\uff0c\u542b\u91d1\u91cf\u5176\u5b9e\u5c31\u53ea\u6709`.gitlab-ci.yml`\u7f16\u5199\uff0c\u7136\u800c\u8fd9\u4e2a\u6211\u4e5f\u662f\u6284\u6a21\u677f\u7684\uff08\u8fd9\u5c31\u662f\u5927\u4e00\u6446\u6ca1\u6709\u641e\u9879\u76ee\u7684\u4e0b\u573a.jpgx3\uff09"}]}}')}}]);